// Sample technology signals from the past week.
// In production: replace with HTTP Request → RSS/HN/ArXiv feeds.
const signals = [
  { id: 's001', title: 'OpenAI releases o3-mini: reasoning model optimized for coding tasks', source: 'TechCrunch', category: 'ai-models', url: 'https://example.com/o3-mini', published_at: '2026-07-11', excerpt: 'New model shows 60% improvement on HumanEval benchmarks at 40% lower cost than o1.' },
  { id: 's002', title: 'Anthropic paper: Constitutional AI v2 — self-correction without human labels', source: 'arXiv', category: 'ai-research', url: 'https://example.com/cai-v2', published_at: '2026-07-10', excerpt: 'New training approach reduces RLHF dependence. Potential to lower fine-tuning costs.' },
  { id: 's003', title: 'Vercel ships AI SDK 4.0 with streaming structured outputs', source: 'Vercel Blog', category: 'developer-tools', url: 'https://example.com/vercel-ai-sdk-4', published_at: '2026-07-09', excerpt: 'Simplifies building LLM features in Next.js. Type-safe streaming responses.' },
  { id: 's004', title: 'HN: "We replaced our entire analytics stack with DuckDB + Parquet"', source: 'Hacker News', category: 'data-engineering', url: 'https://example.com/hn-duckdb', published_at: '2026-07-08', excerpt: '347 upvotes. Teams reporting 10x cost reduction vs Snowflake for workloads under 100GB.' },
  { id: 's005', title: 'Google launches Gemini 2.5 Pro with 2M token context window', source: 'Google Blog', category: 'ai-models', url: 'https://example.com/gemini-2-5', published_at: '2026-07-07', excerpt: 'Context window now covers full codebases. Multimodal. Priced at $3.50/1M input tokens.' },
  { id: 's006', title: 'GitHub Copilot adds multi-file editing and PR review in VS Code', source: 'GitHub Blog', category: 'developer-tools', url: 'https://example.com/copilot-multifile', published_at: '2026-07-06', excerpt: 'Copilot can now propose changes across multiple files in a single session. GA for all paid plans.' },
  { id: 's007', title: 'Ray 3.0 released: unified compute for ML training and serving', source: 'Anyscale Blog', category: 'ml-infrastructure', url: 'https://example.com/ray-3', published_at: '2026-07-05', excerpt: 'Significant API simplification. New autoscaling for inference workloads.' }
];
return [{ json: { signals, total: signals.length, period: 'week of 2026-07-07 to 2026-07-14' } }];

const { signals, total, period } = $input.first().json;
if (!signals || signals.length === 0) {
  throw new Error('No signals to process');
}
const domains = $env.TREND_DOMAINS || 'AI, developer tools, data infrastructure';
const signalText = signals.map((s, i) =>
  `[${i+1}] ${s.title}\nSource: ${s.source} | Category: ${s.category} | Date: ${s.published_at}\nExcerpt: ${s.excerpt}`
).join('\n\n');
const system = `You are a technology strategist writing a weekly trend radar for a product team. You are honest about uncertainty. You focus on practical implications, not hype. Return ONLY valid JSON.`;
const user = `Analyse these ${signals.length} technology signals from ${period} and produce a weekly 'so what for us' digest.

Our domain: ${domains}

Signals:
${signalText}

Return JSON:
{
  "headline_insight": "string — one sentence, the single most important thing this week",
  "signals_analysed": [
    {
      "id": "string",
      "title": "string",
      "category": "string",
      "relevance_to_us": "high|medium|low",
      "so_what": "string — specific implication for our product or team",
      "recommended_response": "investigate|monitor|ignore|act",
      "confidence": "low|medium|high"
    }
  ],
  "watch_list": ["string — things to keep tracking"],
  "actions_to_consider": [{ "action": "string", "urgency": "now|soon|later" }],
  "confidence_overall": "low|medium|high",
  "what_we_dont_know": ["string"]
}`;
return [{ json: { signals, total, period, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prepare Digest Prompt').first().json;
let parsed;
try {
  const content = response.choices?.[0]?.message?.content;
  if (!content) throw new Error('No LLM content');
  parsed = JSON.parse(content);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
const req = ['headline_insight', 'signals_analysed', 'watch_list', 'actions_to_consider'];
const missing = req.filter(k => !parsed[k]);
if (missing.length) return [{ json: { _error: true, reason: `Missing: ${missing.join(',')}` } }];
return [{ json: { _error: false, digest: parsed, meta: { period: upstream.period, signal_count: upstream.total, generated_at: new Date().toISOString() } } }];

const { digest: d, meta: m } = $input.first().json;
const signalLines = (d.signals_analysed || []).map(s =>
  `  [${s.relevance_to_us.toUpperCase()}] ${s.title}\n  So what: ${s.so_what}\n  Response: ${s.recommended_response} (confidence: ${s.confidence})`
).join('\n\n');
const actionLines = (d.actions_to_consider || []).map(a => `  [${a.urgency.toUpperCase()}] ${a.action}`).join('\n');
const watchLines = (d.watch_list || []).map(w => `  - ${w}`).join('\n');
const unknownLines = (d.what_we_dont_know || []).map(u => `  - ${u}`).join('\n');
const report = [
  `TECHNOLOGY TREND RADAR — ${m.period}`,
  `Signals reviewed: ${m.signal_count} | Generated: ${m.generated_at}`,
  `Overall confidence: ${d.confidence_overall}`,
  ``,
  `HEADLINE: ${d.headline_insight}`,
  ``,
  `SIGNALS:`,
  signalLines || '  (none)',
  ``,
  `ACTIONS TO CONSIDER:`,
  actionLines || '  (none)',
  ``,
  `WATCH LIST:`,
  watchLines || '  (none)',
  ``,
  `WHAT WE DO NOT KNOW:`,
  unknownLines || '  (none)',
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
